    --glitch-color-3: #ffff00;
    --scanline-color: rgba(0, 0, 0, 0.5);
    --vignette-opacity: 0.8;
    --font-matrix: 'Courier New', monospace;
    --font-glitch: 'Impact', sans-serif;
}

