    background: repeating-linear-gradient(
        0deg,
        rgba(0, 0, 0, 0.15),
        rgba(0, 0, 0, 0.15) 1px,
        transparent 1px,
        transparent 2px
    );
    pointer-events: none;
    z-index: 100;
    animation: crt-flicker 0.15s infinite;
}

.crt-lines::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: linear-gradient(
        to bottom,
        rgba(255, 255, 255, 0.03) 50%,
        transparent 50%
    );
    background-size: 100% 4px;
    animation: scanline-move 8s linear infinite;
}

@keyframes crt-flicker {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.95; }
}

@keyframes scanline-move {
    0% { background-position: 0 0; }
    100% { background-position: 0 100%; }
}

/* ========================================
   VIGNETTE EFFECT
   ======================================== */

.vignette {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: radial-gradient(
        circle at center,
        transparent 50%,
        rgba(0, 0, 0, var(--vignette-opacity)) 100%
    );
    pointer-events: none;
    z-index: 99;
}

/* ========================================
   GLITCH LAYER
   ======================================== */

.glitch-layer {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
    z-index: 98;
    overflow: hidden;
}

.glitch-layer::before,
.glitch-layer::after {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: var(--matrix-black);
}

.glitch-layer::before {
    background: linear-gradient(
        45deg,
        transparent 49%,
        rgba(0, 255, 65, 0.1) 50%,
        transparent 51%
    );
    animation: glitch-1 2s infinite linear;
}

.glitch-layer::after {
    background: linear-gradient(
        -45deg,
        transparent 49%,
        rgba(0, 255, 65, 0.1) 50%,
        transparent 51%
    );
    animation: glitch-2 2s infinite linear;
}

@keyframes glitch-1 {
    0%, 100% { transform: translateX(-2%); }
    10% { transform: translateX(2%); }
    20% { transform: translateX(-1%); }
    30% { transform: translateX(1%); }
    40% { transform: translateX(0); }
}

@keyframes glitch-2 {
    0%, 100% { transform: translateY(-2%); }
    10% { transform: translateY(2%); }
    20% { transform: translateY(-1%); }
    30% { transform: translateY(1%); }
    40% { transform: translateY(0); }
}

/* ========================================
   CONTENT OVERLAY
   ======================================== */

.content-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    z-index: 10;
    padding: 2rem;
}

.glitch-container {
    text-align: center;
    color: var(--matrix-green);
    text-shadow: 0 0 10px var(--matrix-green),
