.typing-effect {
    font-family: var(--font-matrix);
    font-size: clamp(1rem, 3vw, 1.5rem);
    color: var(--matrix-dark-green);
    max-width: 600px;
    margin: 0 auto;
    line-height: 1.6;
    min-height: 3em;
}

.typing-effect::after {
    content: '';
    display: inline-block;
    width: 0.5em;
    height: 1em;
    background: var(--matrix-green);
    vertical-align: bottom;
    animation: blink 0.5s infinite;
}

@keyframes blink {
    0%, 50% { opacity: 1; }
    51%, 100% { opacity: 0; }
}

/* ========================================
