.interactive-layer {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: 50;
    pointer-events: none;
}

.mouse-follower {
    position: absolute;
    width: 20px;
    height: 20px;
    border: 2px solid var(--matrix-green);
    border-radius: 50%;
    transform: translate(-50%, -50%);
    pointer-events: none;
    transition: width 0.3s, height 0.3s, opacity 0.3s;
    opacity: 0.5;
}

.mouse-follower.active {
    width: 40px;
    height: 40px;
    opacity: 0.8;
    background: radial-gradient(
        circle,
        transparent 60%,
        var(--matrix-green) 100%
    );
}

.cursor-glow {
    position: absolute;
    width: 100px;
    height: 100px;
    border-radius: 50%;
    background: radial-gradient(
        circle,
        transparent 50%,
        rgba(0, 255, 65, 0.1) 100%
    );
    transform: translate(-50%, -50%);
    pointer-events: none;
    transition: opacity 0.3s;
}

.cursor-glow.active {
    opacity: 0.3;
}

/* ========================================
   STATS DISPLAY
   ======================================== */

.stats-display {
    position: fixed;
    bottom: 20px;
    left: 20px;
    color: var(--matrix-green);
    font-family: var(--font-matrix);
    font-size: 0.75rem;
    z-index: 100;
    opacity: 0.7;
}

.stat-item {
    display: inline-flex;
    align-items: center;
    margin-right: 20px;
}

.stat-item .label {
    margin-right: 5px;
}

.stat-item span:last-child {
    color: var(--matrix-green);
}

/* ========================================
   AUDIO VISUALIZER
   ======================================== */

.audio-visualizer {
    position: fixed;
    top: 20px;
    right: 20px;
    display: flex;
    align-items: flex-end;
    gap: 3px;
    z-index: 100;
    opacity: 0.6;
