/**
 * Matrix Rain Animation - Main JavaScript Entry Point
 * 
 * This module initializes and coordinates all animation components:
 * - Gradient background animation
 * - CRT scanline effects
 * - Vignette overlay
 * - Mouse parallax effect
 */

// Import modules (ES modules)
import GradientAnimation from './animation.js';
import CRTEffects from './effects.js';
import ParallaxEffect from './parallax.js';

// Configuration
const CONFIG = {
    animationSpeed: 0.02,
    scanlineOpacity: 0.15,
    vignetteOpacity: 0.6,
    parallaxSensitivity: 0.05,
    canvasSize: 2000, // High resolution for retina displays
};

// Global state
let animationInstance = null;
let effectsInstance = null;
let parallaxInstance = null;

/**
 * Initialize all animation components
 */
function init() {
    console.log('🌈 Initializing Matrix Rain Animation...');

    // Create canvas element if not exists
    if (!document.querySelector('.matrix-bg canvas')) {
        const canvas = document.createElement('canvas');
        canvas.className = 'matrix-bg';
        canvas.width = CONFIG.canvasSize;
        canvas.height = CONFIG.canvasSize;
        document.querySelector('.matrix-bg').appendChild(canvas);
    }

    // Initialize Gradient Animation
    animationInstance = new GradientAnimation({
        speed: CONFIG.animationSpeed,
        canvas: document.querySelector('.matrix-bg canvas'),
        vignette: document.querySelector('.matrix-bg .vignette'),
    });

    // Initialize CRT Effects
    effectsInstance = new CRTEffects({
        scanline: document.querySelector('.matrix-bg .scanlines'),
        vignette: document.querySelector('.matrix-bg .vignette'),
        opacity: CONFIG.scanlineOpacity,
    });

    // Initialize Parallax Effect
    parallaxInstance = new ParallaxEffect({
        container: document.querySelector('.matrix-bg'),
        sensitivity: CONFIG.parallaxSensitivity,
    });

    // Start all animations
    animationInstance.start();
    effectsInstance.start();
    parallaxInstance.start();

    console.log('✨ Matrix Rain Animation initialized successfully!');
}

/**
 * Stop and clean up all animations
 */
function stop() {
    if (animationInstance) {
        animationInstance.stop();
    }
    if (effectsInstance) {
        effectsInstance.stop();
    }
    if (parallaxInstance) {
        parallaxInstance.stop();
    }
    console.log('🛑 Matrix Rain Animation stopped.');
}

/**
 * Update configuration at runtime
 */
function updateConfig(config) {
    Object.assign(CONFIG, config);

    if (animationInstance) {
        animationInstance.updateSpeed(CONFIG.animationSpeed);
    }
    if (effectsInstance) {
        effectsInstance.updateOpacity(CONFIG.scanlineOpacity);
    }
    if (parallaxInstance) {
        parallaxInstance.updateSensitivity(CONFIG.parallaxSensitivity);
    }
}

// Export public API
export { init, stop, updateConfig };

// Auto-initialize when DOM is ready
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
} else {
    init();
}

